+function drawThroneRoom(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Throne (gold with cushion)
+  const tx = x + w * 0.38, ty = y + h * 0.18;
+  const tw = 28, th = 32;
+  // Throne base
+  ctx.fillStyle = '#6b4a10'; ctx.fillRect(tx, ty + 10, tw, th - 10);
+  // Cushion
+  ctx.fillStyle = '#a02525'; ctx.fillRect(tx + 4, ty + 14, tw - 8, 10);
+  // Throne back
+  ctx.fillStyle = '#d4af37'; // gold
+  ctx.fillRect(tx + 2, ty, tw - 4, 12);
+  // Gold details
+  ctx.strokeStyle = '#f5e050';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(tx + 4, ty + 6);
+  ctx.lineTo(tx + tw - 4, ty + 6);
+  ctx.stroke();
+  // Cushion details
+  ctx.fillStyle = '#7a1a1a';
+  for(let i=0; i<3; i++) {
+    ctx.fillRect(tx + 6 + i*8, ty + 18, 2, 6);
+  }
+
+  // Throne armrests
+  ctx.fillStyle = '#6b4a10';
+  ctx.fillRect(tx - 6, ty + 10, 6, th - 10);
+  ctx.fillRect(tx + tw, ty + 10, 6, th - 10);
+  ctx.strokeStyle = '#d4af37';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(tx - 6, ty + 10, 6, 2);
+  ctx.strokeRect(tx + tw, ty + 10, 6, 2);
+
+  // Banner left
+  drawBanner(ctx, x + w * 0.08, y + 4, 18, 38, '#8b1515', '#d4af37');
+  // Banner right
+  drawBanner(ctx, x + w * 0.82, y + 4, 18, 38, '#8b1515', '#d4af37');
+  // Torches
+  drawTorch(ctx, x + w * 0.02, y + h * 0.15, frame);
+  drawTorch(ctx, x + w * 0.92, y + h * 0.15, frame);
+}
+
+function drawCouncilRoom(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Planning Table (wood with map scroll)
+  const tx = x + w * 0.15, ty = y + h * 0.48;
+  const tw = 32, th = 24;
+  // Table base
+  ctx.fillStyle = '#6b4a10'; ctx.fillRect(tx, ty, tw, th);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(tx + 2, ty + 2, tw - 4, th - 4);
+  // Map scroll
+  ctx.fillStyle = '#d4c5a0';
+  ctx.fillRect(tx + 6, ty + 6, tw - 12, th - 12);
+  ctx.strokeStyle = '#8a7a60';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(tx + 6, ty + 6, tw - 12, th - 12);
+  // Map details (simple lines)
+  ctx.strokeStyle = '#7a6a50';
+  ctx.beginPath();
+  ctx.moveTo(tx + 8, ty + 10);
+  ctx.lineTo(tx + tw - 8, ty + th - 10);
+  ctx.moveTo(tx + tw - 8, ty + 10);
+  ctx.lineTo(tx + 8, ty + th - 10);
+  ctx.stroke();
+
+  // Chairs around table
+  drawChair(ctx, tx + 4, ty + th);
+  drawChair(ctx, tx + tw - 10, ty + th);
+
+  // Candles on table
+  drawCandle(ctx, tx + tw - 6, ty - 8, frame, 0);
+  drawCandle(ctx, tx + 4, ty - 8, frame, 30);
+
+  // Tapestry on wall
+  drawTapestry(ctx, x + w * 0.4, y + 4, 30, 28, '#2a1860');
+  // Torch on wall
+  drawTorch(ctx, x + w * 0.02, y + h * 0.12, frame);
+}
+
+function drawWarRoom(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Weapon Rack (with sword silhouettes)
+  const rx = x + w * 0.03, ry = y + h * 0.08;
+  const rw = 32, rh = 32;
+  // Rack base
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(rx, ry, rw, rh);
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(rx + 2, ry + 2, rw - 4, rh - 4);
+  // Sword silhouettes
+  ctx.strokeStyle = '#9a9aaa';
+  ctx.lineWidth = 2;
+  for(let i=0; i<3; i++) {
+    const sx = rx + 6 + i * 10;
+    // Blade
+    ctx.beginPath();
+    ctx.moveTo(sx, ry + 6);
+    ctx.lineTo(sx, ry + rh - 6);
+    ctx.stroke();
+    // Crossguard
+    ctx.beginPath();
+    ctx.moveTo(sx - 4, ry + rh * 0.5);
+    ctx.lineTo(sx + 4, ry + rh * 0.5);
+    ctx.stroke();
+    // Pommel
+    ctx.beginPath();
+    ctx.arc(sx, ry + rh - 4, 2, 0, Math.PI * 2);
+    ctx.fillStyle = '#7a7a7a';
+    ctx.fill();
+  }
+
+  // Shield (blue with gold trim)
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  const shx = rx + rw + 6;
+  ctx.moveTo(shx, ry + 4);
+  ctx.lineTo(shx + 12, ry + 8);
+  ctx.lineTo(shx + 12, ry + 24);
+  ctx.lineTo(shx + 6, ry + 30);
+  ctx.lineTo(shx, ry + 24);
+  ctx.lineTo(shx - 12, ry + 8);
+
